INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme01', 1, 'Pronouns & 1st Group Verbs (-er)', 'Местоимения и глаголы 1-й группы (-er)', 'Learn personal pronouns and regular 1st group (-er) verbs in present tense', 'Личные местоимения и правильные глаголы 1-й группы на -er в настоящем времени', NULL, 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme02', 2, 'Negative Form', 'Отрицательная форма', 'Learn to negate sentences with ne...pas', 'Отрицание с ne...pas', 'theme01', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme03', 3, 'Questions', 'Вопросительная форма', 'Learn to ask questions in French', 'Учимся задавать вопросы по-французски', 'theme02', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme04', 4, 'Etiquette Phrases', 'Фразы этикета', 'Essential polite expressions for everyday French', 'Основные вежливые выражения на каждый день', 'theme03', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme05', 5, 'Verb "avoir"', 'Глагол «avoir» (иметь)', 'Master the essential irregular verb "avoir"', 'Неправильный глагол «avoir» — один из самых важных', 'theme04', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme06', 6, 'Verb "être"', 'Глагол «être» (быть)', 'Master the essential irregular verb "être"', 'Неправильный глагол «être» — один из самых важных', 'theme05', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme07', 7, 'Past Tense (passé composé)', 'Прошедшее время (passé composé)', 'Learn the most common past tense', 'Самое употребительное прошедшее время', 'theme06', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme08', 8, 'Past Tense: Negative & Questions', 'Прошедшее время: отрицание и вопросы', 'Negative and question forms in past tense', 'Отрицательная и вопросительная формы прошедшего времени', 'theme07', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme09', 9, 'Irregular Verbs I', 'Неправильные глаголы I', 'Aller, faire, pouvoir, vouloir', 'Aller, faire, pouvoir, vouloir', 'theme08', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme10', 10, 'Future Tense', 'Будущее время', 'Express future actions', 'Выражение будущего времени', 'theme09', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme11', 11, 'Question Words', 'Вопросительные слова', 'Qui, que, où, quand, comment, pourquoi', 'Кто, что, где, когда, как, почему', 'theme10', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme12', 12, 'Talking About Yourself', 'Рассказ о себе', 'Hobbies, profession, interests', 'Хобби, профессия, интересы', 'theme11', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme13', 13, 'Masculine Nouns & Articles', 'Существительные м.р. и артикли', 'Masculine nouns, singular and plural', 'Существительные мужского рода, ед. и мн. число', 'theme12', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme14', 14, 'Adverbs', 'Наречия', 'Tout, rien, quelqu''un, toujours, jamais...', 'Всё, ничего, кто-то, всегда, никогда...', 'theme13', 60);
