INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme21', 21, 'Days, Months, Directions', 'Дни недели, месяцы, стороны света', 'Calendar vocabulary and cardinal directions', 'Календарь и стороны света', 'theme20', 60);
INSERT INTO theme (id, "order", title, title_ru, description, description_ru, unlock_theme_id, unlock_min_score) VALUES ('theme22', 22, 'Cardinal Numbers', 'Количественные числительные', 'Numbers from 0 to 1000+', 'Числа от 0 до 1000+', 'theme21', 60);
