INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme01', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Личные местоимения","text":"Во французском языке 8 личных местоимений. В отличие от русского, местоимение обязательно используется с глаголом.","examples":[{"fr":"Je","ru":"Я"},{"fr":"Tu","ru":"Ты"},{"fr":"Il / Elle","ru":"Он / Она"},{"fr":"Nous","ru":"Мы"},{"fr":"Vous","ru":"Вы"},{"fr":"Ils / Elles","ru":"Они (м.) / Они (ж.)"}]},{"title":"Три группы французских глаголов","text":"Все французские глаголы делятся на три группы:\n\n• 1-я группа (-er): самая большая и регулярная. Около 90% всех глаголов! Например: parler, manger, aimer, travailler.\n\n• 2-я группа (-ir с -issons): правильные глаголы на -ir. Например: finir → nous finissons, choisir → nous choisissons.\n\n• 3-я группа: все остальные — неправильные глаголы. Например: être, avoir, aller, faire, prendre.\n\nВ этом уроке мы изучаем глаголы 1-й группы — самые простые и частотные.","examples":[{"fr":"parler, manger, aimer, donner","ru":"1-я группа (-er)"},{"fr":"finir, choisir, agir","ru":"2-я группа (-ir)"},{"fr":"être, avoir, aller, faire","ru":"3-я группа (неправильные)"}]},{"title":"Спряжение глаголов 1-й группы (-er)","text":"Чтобы спрягать глаголы 1-й группы, убираем окончание -er от инфинитива — получаем основу (le radical). Затем добавляем окончания: -e, -es, -e, -ons, -ez, -ent. Основа не меняется!","examples":[{"fr":"Je mange","ru":"Я ем"},{"fr":"Tu manges","ru":"Ты ешь"},{"fr":"Il mange","ru":"Он ест"},{"fr":"Nous mangeons","ru":"Мы едим"},{"fr":"Vous mangez","ru":"Вы едите"},{"fr":"Ils mangent","ru":"Они едят"}]}],"tables":[]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme02', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Отрицание ne...pas","text":"Чтобы сделать предложение отрицательным, нужно поставить «ne» перед глаголом и «pas» после него. В разговорной речи «ne» часто опускается.","examples":[{"fr":"Je ne mange pas","ru":"Я не ем"},{"fr":"Tu ne parles pas","ru":"Ты не говоришь"},{"fr":"Il ne mange pas","ru":"Он не ест"},{"fr":"Nous ne parlons pas","ru":"Мы не говорим"},{"fr":"Je ne comprends pas","ru":"Я не понимаю"}]},{"title":"Перед гласной: n''","text":"Когда глагол начинается с гласной, «ne» сокращается до «n''».","examples":[{"fr":"Il n''aime pas","ru":"Он не любит"},{"fr":"Je n''écoute pas","ru":"Я не слушаю"}]}],"tables":[]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme03', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Вопрос интонацией","text":"Самый простой способ задать вопрос — повысить интонацию в конце предложения. Структура остаётся такой же, как в утверждении.","examples":[{"fr":"Tu parles français?","ru":"Ты говоришь по-французски?"},{"fr":"Il mange?","ru":"Он ест?"},{"fr":"Vous comprenez?","ru":"Вы понимаете?"}]},{"title":"Est-ce que","text":"Более формальный способ — добавить «est-ce que» в начало предложения.","examples":[{"fr":"Est-ce que tu parles français?","ru":"Ты говоришь по-французски?"},{"fr":"Est-ce que vous mangez?","ru":"Вы едите?"}]}],"tables":[]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme04', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Приветствия и прощания","text":"Французы придают большое значение вежливости. Всегда здоровайтесь и прощайтесь!","examples":[{"fr":"Bonjour","ru":"Здравствуйте / Добрый день"},{"fr":"Bonsoir","ru":"Добрый вечер"},{"fr":"Au revoir","ru":"До свидания"},{"fr":"Salut","ru":"Привет / Пока (неформ.)"},{"fr":"Bonne nuit","ru":"Спокойной ночи"}]},{"title":"Вежливые выражения","text":"Эти фразы используются постоянно в повседневном общении.","examples":[{"fr":"Merci / Merci beaucoup","ru":"Спасибо / Большое спасибо"},{"fr":"S''il vous plaît","ru":"Пожалуйста (просьба, формальн.)"},{"fr":"S''il te plaît","ru":"Пожалуйста (просьба, неформальн.)"},{"fr":"De rien","ru":"Не за что"},{"fr":"Excusez-moi","ru":"Извините"},{"fr":"Pardon","ru":"Простите"}]},{"title":"Как дела?","text":"Стандартные фразы для начала разговора.","examples":[{"fr":"Comment allez-vous?","ru":"Как вы поживаете? (формальн.)"},{"fr":"Ça va?","ru":"Как дела? (неформальн.)"},{"fr":"Ça va bien, merci","ru":"Хорошо, спасибо"},{"fr":"Et vous?","ru":"А вы?"}]}],"tables":[]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme05', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Глагол avoir — иметь","text":"Avoir — один из двух самых важных глаголов французского языка. Он неправильный и используется как вспомогательный для образования прошедшего времени.","examples":[{"fr":"J''ai","ru":"Я имею"},{"fr":"Tu as","ru":"Ты имеешь"},{"fr":"Il/Elle a","ru":"Он/Она имеет"},{"fr":"Nous avons","ru":"Мы имеем"},{"fr":"Vous avez","ru":"Вы имеете"},{"fr":"Ils/Elles ont","ru":"Они имеют"}]},{"title":"Выражения с avoir","text":"Многие выражения, которые в русском используют «быть», во французском используют «avoir».","examples":[{"fr":"J''ai faim","ru":"Я голоден (букв. «Я имею голод»)"},{"fr":"J''ai soif","ru":"Я хочу пить"},{"fr":"J''ai froid","ru":"Мне холодно"},{"fr":"J''ai chaud","ru":"Мне жарко"},{"fr":"J''ai peur","ru":"Мне страшно"},{"fr":"J''ai 20 ans","ru":"Мне 20 лет"}]}],"tables":[{"verb":"avoir","translation":"иметь","rows":[{"pronoun":"j''","form":"ai","ipa":"/ɛ/"},{"pronoun":"tu","form":"as","ipa":"/a/"},{"pronoun":"il/elle","form":"a","ipa":"/a/"},{"pronoun":"nous","form":"avons","ipa":"/a.vɔ̃/"},{"pronoun":"vous","form":"avez","ipa":"/a.ve/"},{"pronoun":"ils/elles","form":"ont","ipa":"/ɔ̃/"}]}]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme06', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Глагол être — быть","text":"Être — самый важный глагол французского языка наряду с avoir. Он неправильный и используется:\n\n• Как смысловой глагол (быть, являться)\n• Как вспомогательный глагол для passé composé с глаголами движения\n• В конструкциях с прилагательными (описание состояний)\n• Для указания профессии, национальности, местоположения\n\nВ русском языке глагол «быть» в настоящем времени обычно опускается («Я студент»), но во французском он обязателен («Je suis étudiant»).","examples":[{"fr":"Je suis","ru":"Я есть / Я являюсь"},{"fr":"Tu es","ru":"Ты есть / Ты являешься"},{"fr":"Il/Elle est","ru":"Он/Она есть / является"},{"fr":"Nous sommes","ru":"Мы есть / являемся"},{"fr":"Vous êtes","ru":"Вы есть / являетесь"},{"fr":"Ils/Elles sont","ru":"Они есть / являются"}]},{"title":"Être + профессия и национальность","text":"Для указания профессии и национальности используется être БЕЗ артикля (в отличие от многих других языков). Прилагательное согласуется в роде с подлежащим.","examples":[{"fr":"Je suis étudiant / étudiante","ru":"Я студент / студентка"},{"fr":"Il est professeur","ru":"Он преподаватель"},{"fr":"Elle est médecin","ru":"Она врач"},{"fr":"Je suis russe","ru":"Я русский / русская"},{"fr":"Il est français","ru":"Он француз"},{"fr":"Elle est française","ru":"Она француженка"}]},{"title":"Être + прилагательное (описание состояний)","text":"Для описания состояний и качеств используется être + прилагательное. Прилагательное согласуется с подлежащим в роде и числе.","examples":[{"fr":"Je suis fatigué(e)","ru":"Я уставший / уставшая"},{"fr":"Tu es content(e)","ru":"Ты довольный / довольная"},{"fr":"Il est grand","ru":"Он высокий"},{"fr":"Elle est petite","ru":"Она маленькая"},{"fr":"Nous sommes prêts","ru":"Мы готовы"},{"fr":"Ils sont malades","ru":"Они больны"}]},{"title":"Être + местоположение","text":"Для указания местоположения используются конструкции être + à / en / dans.","examples":[{"fr":"Je suis à Paris","ru":"Я в Париже"},{"fr":"Tu es à la maison","ru":"Ты дома"},{"fr":"Il est en France","ru":"Он во Франции"},{"fr":"Nous sommes dans la classe","ru":"Мы в классе"},{"fr":"Vous êtes au bureau","ru":"Вы в офисе"},{"fr":"Elles sont en vacances","ru":"Они в отпуске"}]},{"title":"Конструкция c''est / ce sont","text":"C''est (ед. число) и ce sont (мн. число) — очень частые конструкции для представления и указания на предметы/людей.","examples":[{"fr":"C''est un livre","ru":"Это книга"},{"fr":"C''est mon ami","ru":"Это мой друг"},{"fr":"C''est intéressant","ru":"Это интересно"},{"fr":"Ce sont mes parents","ru":"Это мои родители"},{"fr":"C''est la vie !","ru":"Такова жизнь!"},{"fr":"Qu''est-ce que c''est ?","ru":"Что это?"}]},{"title":"Отрицание с être","text":"Отрицание строится по общему правилу: ne + être + pas. В разговорной речи ne часто опускается.","examples":[{"fr":"Je ne suis pas français","ru":"Я не француз"},{"fr":"Tu n''es pas fatigué ?","ru":"Ты не устал?"},{"fr":"Il n''est pas là","ru":"Его здесь нет"},{"fr":"Ce n''est pas vrai","ru":"Это неправда"},{"fr":"Nous ne sommes pas prêts","ru":"Мы не готовы"},{"fr":"Elles ne sont pas d''accord","ru":"Они не согласны"}]}],"tables":[{"verb":"être","translation":"быть","rows":[{"pronoun":"je","form":"suis","ipa":"/sɥi/"},{"pronoun":"tu","form":"es","ipa":"/ɛ/"},{"pronoun":"il/elle","form":"est","ipa":"/ɛ/"},{"pronoun":"nous","form":"sommes","ipa":"/sɔm/"},{"pronoun":"vous","form":"êtes","ipa":"/ɛt/"},{"pronoun":"ils/elles","form":"sont","ipa":"/sɔ̃/"}]}]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme07', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Что такое passé composé?","text":"Passé composé — самое употребительное прошедшее время во французском языке. Оно используется для завершённых действий в прошлом. Аналог русского прошедшего времени совершенного вида.\n\nОно называется «составным» (composé), потому что состоит из двух частей:\n\n• Вспомогательный глагол (avoir или être) в настоящем времени\n• Причастие прошедшего времени (participe passé) основного глагола","examples":[{"fr":"J''ai mangé","ru":"Я поел / Я ел"},{"fr":"Tu as parlé","ru":"Ты поговорил"},{"fr":"Il a travaillé","ru":"Он поработал"},{"fr":"Nous avons chanté","ru":"Мы пели / Мы спели"}]},{"title":"Образование participe passé глаголов 1-й группы (-er)","text":"Для глаголов 1-й группы всё просто: убираем -er и добавляем -é.\n\nparler → parlé\nmanger → mangé\naimer → aimé\ntravailler → travaillé\nchanter → chanté\n\nЭто самая большая и регулярная группа. Запомните формулу: основа + é.","examples":[{"fr":"parler → parlé","ru":"говорить → говорённый"},{"fr":"manger → mangé","ru":"есть → съеденный"},{"fr":"aimer → aimé","ru":"любить → любимый"},{"fr":"travailler → travaillé","ru":"работать → отработанный"},{"fr":"danser → dansé","ru":"танцевать → танцевавший"},{"fr":"chercher → cherché","ru":"искать → искавший"}]},{"title":"Спряжение с avoir","text":"Большинство глаголов (около 90%) образуют passé composé с вспомогательным глаголом avoir. Вы уже знаете его спряжение из урока 5!\n\nФормула: avoir в настоящем времени + participe passé","examples":[{"fr":"J''ai parlé","ru":"Я говорил / поговорил"},{"fr":"Tu as mangé","ru":"Ты ел / поел"},{"fr":"Il a chanté","ru":"Он пел / спел"},{"fr":"Elle a dansé","ru":"Она танцевала"},{"fr":"Nous avons travaillé","ru":"Мы работали / поработали"},{"fr":"Vous avez écouté","ru":"Вы слушали / послушали"},{"fr":"Ils ont joué","ru":"Они играли / поиграли"},{"fr":"Elles ont regardé","ru":"Они смотрели / посмотрели"}]},{"title":"Глаголы движения с être","text":"Около 15 глаголов (в основном глаголы движения и изменения состояния) образуют passé composé с être вместо avoir. Запомните их с помощью «дома DR & MRS VANDERTRAMP»:\n\nDevenir, Revenir, Monter, Rester, Sortir, Venir, Aller, Naître, Descendre, Entrer, Retourner, Tomber, Rentrer, Arriver, Mourir, Partir\n\nВажно: при использовании être причастие согласуется с подлежащим в роде и числе!","examples":[{"fr":"Je suis allé(e)","ru":"Я пошёл / пошла"},{"fr":"Tu es arrivé(e)","ru":"Ты пришёл / пришла"},{"fr":"Il est tombé","ru":"Он упал"},{"fr":"Elle est tombée","ru":"Она упала (добавляем -e!)"},{"fr":"Nous sommes partis","ru":"Мы ушли (добавляем -s!)"},{"fr":"Elles sont arrivées","ru":"Они (ж.) пришли (добавляем -es!)"}]},{"title":"Согласование с être","text":"Когда вспомогательный глагол — être, причастие ведёт себя как прилагательное и согласуется с подлежащим:\n\n• Мужской род, ед. число: без изменений (allé)\n• Женский род, ед. число: +e (allée)\n• Мужской род, мн. число: +s (allés)\n• Женский род, мн. число: +es (allées)","examples":[{"fr":"Il est parti","ru":"Он ушёл"},{"fr":"Elle est partie","ru":"Она ушла"},{"fr":"Ils sont partis","ru":"Они (м.) ушли"},{"fr":"Elles sont parties","ru":"Они (ж.) ушли"}]},{"title":"Participe passé неправильных глаголов","text":"Некоторые частые глаголы имеют неправильное причастие. Их нужно запоминать:","examples":[{"fr":"avoir → eu","ru":"иметь → имевший"},{"fr":"être → été","ru":"быть → бывший"},{"fr":"faire → fait","ru":"делать → сделанный"},{"fr":"prendre → pris","ru":"брать → взятый"},{"fr":"mettre → mis","ru":"класть → положенный"},{"fr":"voir → vu","ru":"видеть → увиденный"},{"fr":"dire → dit","ru":"говорить → сказанный"},{"fr":"écrire → écrit","ru":"писать → написанный"},{"fr":"lire → lu","ru":"читать → прочитанный"},{"fr":"boire → bu","ru":"пить → выпитый"},{"fr":"pouvoir → pu","ru":"мочь → смогший"},{"fr":"vouloir → voulu","ru":"хотеть → хотевший"},{"fr":"savoir → su","ru":"знать → узнавший"},{"fr":"venir → venu","ru":"приходить → пришедший"}]},{"title":"Маркеры времени для passé composé","text":"Эти слова-подсказки часто указывают на passé composé:","examples":[{"fr":"hier","ru":"вчера"},{"fr":"la semaine dernière","ru":"на прошлой неделе"},{"fr":"l''année dernière","ru":"в прошлом году"},{"fr":"il y a deux jours","ru":"два дня назад"},{"fr":"ce matin","ru":"сегодня утром"},{"fr":"déjà","ru":"уже"}]}],"tables":[{"verb":"avoir (вспомогательный)","translation":"иметь","rows":[{"pronoun":"j''","form":"ai","ipa":"/ɛ/"},{"pronoun":"tu","form":"as","ipa":"/a/"},{"pronoun":"il/elle","form":"a","ipa":"/a/"},{"pronoun":"nous","form":"avons","ipa":"/a.vɔ̃/"},{"pronoun":"vous","form":"avez","ipa":"/a.ve/"},{"pronoun":"ils/elles","form":"ont","ipa":"/ɔ̃/"}]},{"verb":"être (вспомогательный)","translation":"быть","rows":[{"pronoun":"je","form":"suis","ipa":"/sɥi/"},{"pronoun":"tu","form":"es","ipa":"/ɛ/"},{"pronoun":"il/elle","form":"est","ipa":"/ɛ/"},{"pronoun":"nous","form":"sommes","ipa":"/sɔm/"},{"pronoun":"vous","form":"êtes","ipa":"/ɛt/"},{"pronoun":"ils/elles","form":"sont","ipa":"/sɔ̃/"}]}]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme08', 'grammar', 0, '{"type":"grammar","notes":[{"title":"Отрицание в passé composé","text":"В passé composé частицы отрицания ne...pas окружают вспомогательный глагол (avoir или être), а НЕ причастие. Причастие всегда стоит после pas.\n\nФормула: Подлежащее + ne + avoir/être + pas + participe passé\n\nВажно: «ne» сокращается до «n''» перед гласной (n''ai, n''est, n''ont).","examples":[{"fr":"Je n''ai pas mangé","ru":"Я не ел / Я не поел"},{"fr":"Tu n''as pas parlé","ru":"Ты не говорил"},{"fr":"Il n''a pas travaillé","ru":"Он не работал"},{"fr":"Nous n''avons pas chanté","ru":"Мы не пели"},{"fr":"Vous n''avez pas écouté","ru":"Вы не слушали"},{"fr":"Ils n''ont pas joué","ru":"Они не играли"}]},{"title":"Отрицание с глаголами на être","text":"Для глаголов, спрягающихся с être, правило то же самое: ne...pas окружают être. Причастие стоит после pas и по-прежнему согласуется с подлежащим.","examples":[{"fr":"Je ne suis pas allé(e)","ru":"Я не пошёл / не пошла"},{"fr":"Elle n''est pas arrivée","ru":"Она не приехала"},{"fr":"Il n''est pas parti","ru":"Он не ушёл"},{"fr":"Nous ne sommes pas sortis","ru":"Мы не вышли"},{"fr":"Elles ne sont pas tombées","ru":"Они (ж.) не упали"}]},{"title":"Другие формы отрицания","text":"Кроме ne...pas, во французском есть и другие отрицательные конструкции. Они работают по тому же принципу — окружают вспомогательный глагол:\n\n• ne...jamais — никогда\n• ne...rien — ничего\n• ne...plus — больше не\n• ne...personne — никого (но personne стоит ПОСЛЕ причастия!)\n• ne...pas encore — ещё не","examples":[{"fr":"Je n''ai jamais visité Paris","ru":"Я никогда не посещал Париж"},{"fr":"Il n''a rien mangé","ru":"Он ничего не ел"},{"fr":"Elle n''a plus travaillé","ru":"Она больше не работала"},{"fr":"Je n''ai vu personne","ru":"Я никого не видел (personne после причастия!)"},{"fr":"Tu n''as pas encore fini","ru":"Ты ещё не закончил"}]},{"title":"Три способа задать вопрос в passé composé","text":"Во французском языке есть три способа образования вопроса. Все три работают и в passé composé:\n\n1. Интонация (разговорный) — просто поднимите голос в конце. Самый простой способ.\n\n2. Est-ce que (нейтральный) — добавьте «est-ce que» в начало. Универсальный вариант.\n\n3. Инверсия (формальный) — поменяйте местами подлежащее и вспомогательный глагол. Используется в письменной речи и формальном общении.","examples":[{"fr":"Tu as mangé ?","ru":"Ты ел? (интонация)"},{"fr":"Est-ce que tu as mangé ?","ru":"Ты ел? (est-ce que)"},{"fr":"As-tu mangé ?","ru":"Ты ел? (инверсия)"}]},{"title":"Вопросы с инверсией: подробности","text":"При инверсии вспомогательный глагол и местоимение соединяются дефисом. В 3-м лице добавляется -t- между гласными для благозвучия.\n\nС être — тот же принцип: Est-il parti? Est-elle arrivée?\n\nС именным подлежащим используется «двойная» конструкция: Marie est-elle partie?","examples":[{"fr":"Ai-je bien compris ?","ru":"Правильно ли я понял?"},{"fr":"As-tu fini ?","ru":"Ты закончил?"},{"fr":"A-t-il mangé ?","ru":"Он ел? (-t- для благозвучия)"},{"fr":"A-t-elle parlé ?","ru":"Она говорила?"},{"fr":"Avons-nous choisi ?","ru":"Мы выбрали?"},{"fr":"Avez-vous compris ?","ru":"Вы поняли?"},{"fr":"Ont-ils travaillé ?","ru":"Они работали?"},{"fr":"Est-il parti ?","ru":"Он ушёл?"},{"fr":"Est-elle arrivée ?","ru":"Она приехала?"},{"fr":"Marie a-t-elle téléphoné ?","ru":"Мари звонила?"}]},{"title":"Вопросительные слова + passé composé","text":"Вопросительные слова ставятся в начало предложения. После них можно использовать est-ce que или инверсию:\n\n• Où — где / куда\n• Quand — когда\n• Pourquoi — почему\n• Comment — как\n• Combien — сколько\n• Que / Qu'' — что","examples":[{"fr":"Où est-ce que tu as mangé ?","ru":"Где ты ел?"},{"fr":"Où as-tu mangé ?","ru":"Где ты ел? (инверсия)"},{"fr":"Quand est-il arrivé ?","ru":"Когда он приехал?"},{"fr":"Pourquoi n''as-tu pas téléphoné ?","ru":"Почему ты не позвонил?"},{"fr":"Comment a-t-elle fait ?","ru":"Как она это сделала?"},{"fr":"Qu''est-ce que vous avez mangé ?","ru":"Что вы ели?"},{"fr":"Qu''avez-vous fait ?","ru":"Что вы сделали?"}]},{"title":"Отрицательные вопросы","text":"Отрицательный вопрос = вопрос + отрицание. Используется, когда вы удивлены или ожидаете определённый ответ.\n\nС est-ce que: Est-ce que tu n''as pas...?\nС инверсией: N''as-tu pas...?\nРазговорный: Tu n''as pas...?","examples":[{"fr":"Tu n''as pas mangé ?","ru":"Ты не ел? (разговорный)"},{"fr":"Est-ce que tu n''as pas compris ?","ru":"Ты не понял?"},{"fr":"N''avez-vous pas reçu mon message ?","ru":"Вы не получили моё сообщение?"},{"fr":"N''est-elle pas venue ?","ru":"Разве она не пришла?"}]}],"tables":[]}');
INSERT INTO theme_section (theme_id, type, sort_order, content) VALUES ('theme08', 'exercises', 1, '{"type":"exercises","exercises":[{"type":"multiple_choice","prompt":"Выберите правильную отрицательную форму: \"Я не ел\"","options":["Je n''ai pas mangé","Je ne pas ai mangé","Je n''ai mangé pas","Je pas n''ai mangé"],"correctIndex":0},{"type":"fill_blank","sentence":"Elle ___ arrivée hier","answer":"n''est pas"},{"type":"fill_blank","sentence":"Nous ___ regardé ce film","answer":"n''avons pas"},{"type":"multiple_choice","prompt":"Как сказать \"Он никогда не работал\" ?","options":["Il n''a jamais travaillé","Il n''a pas jamais travaillé","Il ne jamais a travaillé","Il a jamais ne travaillé"],"correctIndex":0},{"type":"translation","prompt":"Переведите: Ты ел? (инверсия)","answer":"As-tu mangé"},{"type":"multiple_choice","prompt":"Выберите правильный вопрос с инверсией: \"Она приехала?\"","options":["Est-elle arrivée ?","A-elle arrivée ?","Est arrivée-elle ?","Elle est arrivée ?"],"correctIndex":0},{"type":"fill_blank","sentence":"___-vous compris la leçon ?","answer":"Avez"},{"type":"multiple_choice","prompt":"Где стоит «personne» в отрицании passé composé?","options":["После причастия (participe passé)","Между ne и вспомогательным глаголом","После ne, перед вспомогательным глаголом","В начале предложения"],"correctIndex":0},{"type":"translation","prompt":"Переведите: Где вы работали?","answer":"Où avez-vous travaillé"},{"type":"fill_blank","sentence":"Pourquoi ___-tu ___ téléphoné ?","answer":"n''as pas"},{"type":"matching","pairs":[{"left":"Je n''ai pas mangé","right":"Я не ел"},{"left":"Il n''a jamais parlé","right":"Он никогда не говорил"},{"left":"Elle n''a rien vu","right":"Она ничего не видела"},{"left":"Nous n''avons plus joué","right":"Мы больше не играли"},{"left":"Tu n''as pas encore fini","right":"Ты ещё не закончил"}]},{"type":"multiple_choice","prompt":"A-t-il mangé ? — Зачем здесь «-t-» ?","options":["Для благозвучия между двумя гласными","Это часть спряжения avoir","Это местоимение tu","Это показатель вопроса"],"correctIndex":0}]}');
